const tg = $input.first().json;
const msg = tg.message || tg.edited_message;
if (!msg) return [];
if (msg.from && msg.from.is_bot) return [];
const text = (msg.text || msg.caption || '').trim();

// Parse /start ref_CODE (from referral link t.me/bot?start=ref_CODE)
let ref_code = null;
const startMatch = text.match(/^\/start\s+ref_([A-Z0-9]{6,12})$/i);
if (startMatch) ref_code = startMatch[1].toUpperCase();

const message_text = text || '(клиент прислал НЕ текстовое сообщение — фото/голос/стикер/гео, текста нет. Ответь мило и по-кошачьи, что пока понимаешь только текст, и мягко попроси написать словами)';
const from = msg.from || {};
return [{ json: {
  tg_chat_id: String(msg.chat.id),
  message_text: message_text,
  name: [from.first_name, from.last_name].filter(Boolean).join(' ') || 'Гость',
  language: from.language_code || 'ru',
  ref_code: ref_code
}}];

const ai = $input.first().json;
const prev = $('✍️ Собрать промпт').first().json;
let reply = 'Извините, что-то пошло не так. Попробуйте через минуту 🙏';
try {
  if (ai.error) {
    const code = ai.error.code || ai.error.status || '';
    if (code === 429 || String(code).includes('RESOURCE_EXHAUSTED')) {
      reply = 'Секунду, немного перегружен — напишите ещё раз через минуту 🙏';
    } else if (code === 401 || code === 403) {
      reply = 'Технические неполадки, уже разбираемся!';
    } else if (code === 500 || code === 503) {
      reply = 'Временные неполадки с ИИ. Попробуйте через пару минут 🙏';
    } else {
      reply = 'Что-то пошло не так. Попробуйте ещё раз 🙏';
    }
  } else {
    const text = ai.choices?.[0]?.message?.content;
    if (text && text.trim()) reply = text.trim();
  }
} catch(e) {}

// --- Бронь: технический блок [[BRON]]...[[/BRON]] ---
let booking_ready = false; let booking = null;
const _bm = reply.match(/\[\[BRON\]\]([\s\S]*?)\[\[\/BRON\]\]/i);
if (_bm) {
  const o = {};
  _bm[1].trim().split('\n').forEach(line => { const i = line.indexOf(':'); if (i > 0) o[line.slice(0,i).trim().toLowerCase()] = line.slice(i+1).trim(); });
  // числа: цифры ИЛИ прописью
  const WORDS = {'ноль':0,'один':1,'одна':1,'одного':1,'двое':2,'два':2,'две':2,'двоих':2,'трое':3,'три':3,'троих':3,'четверо':4,'четыре':4,'четверых':4,'пятеро':5,'пять':5,'шесть':6,'семь':7,'восемь':8,'девять':9,'десять':10};
  const num = v => { const s=String(v==null?'':v).toLowerCase(); const d=s.replace(/\D/g,''); if(d){const k=parseInt(d,10);return isNaN(k)?0:k;} for(const w in WORDS) if(s.includes(w)) return WORDS[w]; return 0; };
  // санитайз строк: убрать HTML, кавычки/бэкслэши/переводы строк (защита от JSON-инъекции и краша HTML)
  const clean = v => String(v==null?'':v).replace(/<[^>]*>/g,'').replace(/[\\"]/g,"'").replace(/[\r\n\t]+/g,' ').trim().slice(0,200);
  const phoneNorm = v => { let p=String(v==null?'':v).replace(/[^\d+]/g,''); if(p.indexOf('+')>0) p=p.replace(/\+/g,''); return p; };
  booking = {
    name: clean(o['имя'] || prev.client_name || ''),
    phone: phoneNorm(o['телефон'] || ''),
    tour: clean(o['тур'] || ''),
    date: clean(o['дата'] || ''),
    hotel: clean(o['отель'] || ''),
    room: clean(o['комната'] || ''),
    adults: num(o['взрослых']), children: num(o['детей']), infants: num(o['младенцев']),
    tour_slug: clean(o['тур_slug']||'').replace(/[^a-z0-9\-_]/gi,'')
  };
  booking.total = booking.adults + booking.children + booking.infants;
  booking.external_id = 'tg_' + (prev.tg_chat_id || '') + '_' + (booking.tour_slug||'x') + '_' + (booking.date_iso||'nd');
  booking.date_iso = (o['дата_iso'] && /^\d{4}-\d{2}-\d{2}$/.test(o['дата_iso'].trim())) ? o['дата_iso'].trim() : null;
  // GUARD: бронь готова только если имя + телефон(>=10 цифр) + слаг + хотя бы 1 взрослый
  const phoneOk = booking.phone.replace(/\D/g,'').length >= 10;
  booking_ready = !!(booking.name && phoneOk && booking.tour_slug && booking.adults > 0);
  reply = reply.replace(/\[\[BRON\]\][\s\S]*?\[\[\/BRON\]\]/i, '').trim();
  if (!reply) reply = booking_ready ? 'Готово! Передаю менеджеру — он свяжется с вами в ближайшее время 🐾' : 'Почти готово — давайте уточним пару деталей 🐾';
}
return [{ json: { ...prev, ai_reply: reply, booking_ready, booking } }];

const d = $('💬 Достать ответ').first().json;
const text = (d.message_text || '').toLowerCase();

// Interests
const interests = [];
if (/остров|море|пляж|пхи|симил|джеймс|снорклинг|яхт|морск|дайв|кораллы|плавани/i.test(text)) interests.push('islands');
if (/актив|рафтинг|atv|квадро|мото|зиплайн|гиббон|слон|адренал|спорт|экстрим/i.test(text)) interests.push('active');
if (/природ|джунгли|као.*сок|водопад|лес|нацпарк|эко|нетронут/i.test(text)) interests.push('nature');
if (/вечер|шоу|фаер|тиффани|муай|бокс|закат|романтик|ужин|кабаре/i.test(text)) interests.push('evening');
if (/дети|ребен|детей|малыш|семейн|ребёнок/i.test(text)) interests.push('family');
if (/vip|яхта|премиум|luxury|эксклюзив|персональн/i.test(text)) interests.push('vip');

// Budget
let budget = null;
if (/недорого|дёшево|дешево|бюджетн|экономн/i.test(text)) budget = 'low';
if (/деньги.*не.*вопрос|любой бюджет|vip|премиум/i.test(text)) budget = 'vip';

// --- Arrival date (исправленная эвристика года + DD.MM + DD месяц + завтра) ---
let arrivalDate = null;
const now = new Date();
const curY = now.getFullYear(), curM = now.getMonth() + 1, curD = now.getDate();
const pad = n => String(n).padStart(2, '0');
const yearFor = (mm, dd) => (mm < curM || (mm === curM && dd && dd < curD)) ? curY + 1 : curY;
const months = [['январ','1'],['феврал','2'],['март','3'],['апрел','4'],['ма','5'],['июн','6'],['июл','7'],['август','8'],['сентябр','9'],['октябр','10'],['ноябр','11'],['декабр','12']];
// завтра / послезавтра
if (/послезавтра/.test(text)) { const a=new Date(now); a.setDate(curD+2); arrivalDate=a.toISOString().slice(0,10); }
else if (/завтра/.test(text)) { const a=new Date(now); a.setDate(curD+1); arrivalDate=a.toISOString().slice(0,10); }
// DD.MM (или DD/MM)
if (!arrivalDate) { const m=text.match(/\b(\d{1,2})[.\/](\d{1,2})(?:[.\/](\d{2,4}))?\b/); if(m){ const dd=+m[1], mm=+m[2]; if(dd>=1&&dd<=31&&mm>=1&&mm<=12){ let yy=m[3]?(+m[3]<100?2000+ +m[3]:+m[3]):yearFor(mm,dd); arrivalDate=`${yy}-${pad(mm)}-${pad(dd)}`; } } }
// DD <месяц> или просто <месяц>
if (!arrivalDate) { for (const [name,num] of months){ if(text.includes(name)){ const mm=+num; const dm=text.match(new RegExp('(\\d{1,2})\\s*'+name)); if(dm){ const dd=+dm[1]; arrivalDate=`${yearFor(mm,dd)}-${pad(mm)}-${pad(dd)}`; } else { arrivalDate=`${yearFor(mm,null)}-${pad(mm)}`; } break; } } }
// через N дней/недель
if (!arrivalDate && /через\s+(\d+)\s+(день|дня|дней|недел)/i.test(text)) { const m=text.match(/через\s+(\d+)\s+(день|дня|дней|недел)/i); const days=parseInt(m[1])*(m[2].startsWith('недел')?7:1); const a=new Date(now); a.setDate(curD+days); arrivalDate=a.toISOString().slice(0,10); }

// --- Group & children (суммируем взрослых+детей; вдвоём/втроём) ---
let groupSize = null, hasChildren = null;
const adM = text.match(/(\d+)\s*взросл/);
const chM = text.match(/(\d+)\s*(?:дет|реб)/);
if (adM || chM) { groupSize = (adM?+adM[1]:0) + (chM?+chM[1]:0) || null; }
if (!groupSize) { const gm = text.match(/нас\s+(\d+)|(\d+)\s*человек/); if (gm) groupSize = parseInt(gm[1]||gm[2]) || null; }
if (!groupSize) { const words={'вдвоём':2,'вдвоем':2,'втроём':3,'втроем':3,'вчетвером':4,'впятером':5,'двое':2,'трое':3,'четверо':4,'пятеро':5}; for(const w in words){ if(text.includes(w)){ groupSize=words[w]; break; } } }
if (/дети|ребен|детей|малыш|с детьми|ребёнок/i.test(text)) hasChildren = true;
if (/без детей|только взросл|детей нет/i.test(text)) hasChildren = false;

// --- Stage (убрано одиночное «давай/беру») ---
let stage = null;
if (/забронир|оформ(?:и|ля|лен)|хочу.*(забронир|оформ|купит|брон)|запиш|оплат|купить тур|как заброн|бронирую|готов.*брон/i.test(text)) {
  stage = 'booking';
} else if (/понравил|отлично|супер|незабываем|спасибо за тур|было здорово/i.test(text)) {
  stage = 'done';
} else if (/потом|подумаю|позже|не сейчас|может быть|посмотрим/i.test(text)) {
  stage = 'thinking';
} else if (interests.length || budget || arrivalDate || groupSize) {
  stage = 'interest';
}

// Last tour
let lastTour = null;
const tourMap = [[/джеймс.*бонд|james.*bond/i,'james'],[/пхи.пхи|phi.phi/i,'phiphi-bamboo'],[/симилан/i,'similan'],[/мото.?тур|мотоцикл.*остров/i,'moto'],[/рафтинг|слоны.*atv|atv.*слон/i,'raft'],[/гиббон|зиплайн/i,'gibbon'],[/као.*сок/i,'khaosok2'],[/яхт/i,'yacht'],[/фаер.*шоу|fire.*show/i,'fire'],[/ко.*лан|ko.*lan/i,'kolan'],[/тиффани/i,'tiffany'],[/нонг.*нуч/i,'nong-nooch'],[/рамаян|аквапарк/i,'aqua-ramayana'],[/катамаран|закат/i,'sunset-cat'],[/кхао.*кхео|сафари/i,'khao-kheo']];
for (const [re, slug] of tourMap) { if (re.test(text)) { lastTour = slug; break; } }

return [{ json: {
  client_id: d.client_id, tg_chat_id: d.tg_chat_id, client_name: d.client_name, client_stage: d.client_stage,
  interests: interests.length ? interests : null,
  budget_level: budget,
  new_stage: d.booking_ready ? 'booking' : stage,
  last_tour_viewed: lastTour,
  arrival_date: arrivalDate,
  group_size: groupSize,
  has_children: hasChildren,
  has_updates: !!(interests.length || budget || lastTour || arrivalDate || groupSize || hasChildren !== null || stage) || !!d.booking_ready,
  has_stage_update: !!stage || !!d.booking_ready,
  booking_ready: d.booking_ready || false,
  booking: d.booking || null
}}];
